import React from 'react';
import { useEditor, EditorContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';

const Editor = () => {
  const editor = useEditor({
    extensions: [
      StarterKit,
      // Voeg hier eventuele andere TipTap extensies toe
    ],
    content: '<p>Dit is de initiele content van de TipTap editor.</p>',
    editorProps: {
      attributes: {
        class: 'prose prose-sm sm:prose lg:prose-lg xl:prose-xl m-5 focus:outline-none',
      },
    },
  });

  if (!editor) {
    return null;
  }

  return (
    <div className="editor-container border rounded p-2">
      <EditorContent editor={editor} />
    </div>
  );
};

export default Editor;

async function requestOpenFileHandle() {
  try {
    const [fileHandle] = await window.showOpenFilePicker();
    return fileHandle;
  } catch (error) {
    // Handle errors, e.g., if the user cancels the picker
    if (error.name === 'AbortError') {
      console.log('File picker was dismissed.');
    } else {
      console.error('Error opening file:', error);
    }
    return null; // Or re-throw the error, depending on desired behavior
  }
}

/**
 * Leest de inhoud van een bestand via een FileSystemFileHandle en retourneert deze als een string.
 * @param {FileSystemFileHandle} fileHandle - Het bestandshandle object.
 * @returns {Promise<string>} Een Promise die de inhoud van het bestand als string oplost.
 * @throws {Error} Gooit een fout als het lezen van het bestand mislukt.
 */
async function readFileContent(fileHandle) {
  try {
    const file = await fileHandle.getFile();
    const content = await file.text();
    return content;
  } catch (error) {
    console.error("Fout bij het lezen van bestandsinhoud:", error);
    throw error; // Gooi de fout opnieuw zodat de aanroeper deze kan afhandelen.
  }
}

/**
 * Schrijft de gegeven content naar het opgegeven bestand via een FileSystemFileHandle.
 * Deze functie is bedoeld voor gebruik in een browseromgeving met de File System Access API.
 * @param {FileSystemFileHandle} fileHandle - Het bestandshandle om naar te schrijven.
 * @param {string} content - De content die naar het bestand moet worden geschreven.
 */
async function writeFileContent(fileHandle, content) {
  try {
    // Creëer een FileSystemWritableFileStream om naar te schrijven.
    const writable = await fileHandle.createWritable();
    // Schrijf de inhoud van het bestand naar de stream.
    await writable.write(content);
    // Sluit het bestand en schrijf de inhoud naar de schijf.
    await writable.close();
    console.log('Bestand succesvol geschreven.');
  } catch (error) {
    console.error('Fout bij het schrijven van het bestand:', error);
    throw error;
  }
}

