document.addEventListener('DOMContentLoaded', () => {
    const saveButton = document.getElementById('saveButton');
    const fileContent = document.getElementById('fileContent');

    saveButton.addEventListener('click', async () => {
        if ('showSaveFilePicker' in window) {
            try {
                // Opties voor de opslagdialoog
                const options = {
                    suggestedName: 'nieuw_document.txt',
                    types: [
                        {
                            description: 'Tekstbestanden',
                            accept: { 'text/plain': ['.txt'] },
                        },
                        {
                            description: 'Alle bestanden',
                            accept: { '*/*': ['.*'] },
                        },
                    ],
                };

                // Open de 'opslaan als' dialoog
                const fileHandle = await window.showSaveFilePicker(options);

                // Maak een WritableStream om naar het bestand te schrijven
                const writableStream = await fileHandle.createWritable();

                // Schrijf de inhoud van de textarea naar de stream
                await writableStream.write(fileContent.value);

                // Sluit de stream
                await writableStream.close();

                alert('Bestand succesvol opgeslagen!');
            } catch (error) {
                if (error.name === 'AbortError') {
                    console.log('Opslaan geannuleerd door gebruiker.');
                } else {
                    console.error('Fout bij opslaan van bestand:', error);
                    alert('Fout bij opslaan van bestand: ' + error.message);
                }
            }
        } else {
            alert('Uw browser ondersteunt de File System Access API niet. Gebruik een moderne browser zoals Chrome, Edge of Opera.');
